const rollup = require("rollup");
const path = require("path");
const omt = require(".");
const fs = require("fs");
const chalk = require("chalk");

const karma = require("karma");
const myKarmaConfig = require("./karma.conf.jsx");

async function fileExists(file) {
  try {
    const stat = await fs.promises.stat(file);
    return stat.isFile();
  } catch (e) {
    return false;
  }
}

async function init() {
  await Promise.all(
    [
      "./tests/fixtures/simple-bundle/entry.jsx",
      "./tests/fixtures/import-meta/entry.jsx",
      "./tests/fixtures/dynamic-import/entry.jsx",
      "./tests/fixtures/public-path/entry.jsx",
      "./tests/fixtures/worker/entry.jsx",
      "./tests/fixtures/module-worker/entry.jsx",
      "./tests/fixtures/more-workers/entry.jsx",
      "./tests/fixtures/amd-function-name/entry.jsx",
      "./tests/fixtures/single-default/entry.jsx",
      "./tests/fixtures/import-worker-url/entry.jsx",
      "./tests/fixtures/import-meta-worker/entry.jsx",
      "./tests/fixtures/import-worker-url-custom-scheme/entry.jsx",
      "./tests/fixture../assets-in-worker/entry.jsx",
      "./tests/fixtures/url-import-meta-worker/entry.jsx"
    ].map(async input => {
      const pathName = path.dirname(input);
      const outputOptions = {
        dir: path.join(pathName, "build"),
        format: "amd"
      };
      let rollupConfig = {
        input,
        strictDeprecations: true,
        // Copied / adapted from default `onwarn` in Rollup CLI.
        onwarn: warning => {
          console.warn(`⚠️   ${chalk.bold(warning.message)}`);

          if (warning.url) {
            console.warn(chalk.cyan(warning.url));
          }

          if (warning.loc) {
            console.warn(
              `${warning.loc.file} (${warning.loc.line}:${warning.loc.column})`
            );
          }

          if (warning.frame) {
            console.warn(chalk.dim(warning.frame));
          }

          console.warn("");
        }
      };
      const rollupConfigPath = "./" + path.join(pathName, "rollup.config.jsx");
      const configPath = "./" + path.join(pathName, "config.json");
      if (await fileExists(rollupConfigPath)) {
        require(rollupConfigPath)(rollupConfig, outputOptions, omt);
      } else if (await fileExists(configPath)) {
        rollupConfig.plugins = [omt(require(configPath))];
      } else {
        rollupConfig.plugins = [omt()];
      }
      const bundle = await rollup.rollup(rollupConfig);
      await bundle.write(outputOptions);
    })
  );

  const karmaConfig = { port: 9876 };
  myKarmaConfig({
    set(config) {
      Object.assign(karmaConfig, config);
    }
  });
  const server = new karma.Server(karmaConfig, code => {
    console.log(`Karma exited with code ${code}`);
    process.exit(code);
  });
  server.start();
}
init();
